// ignore_for_file: dangling_library_doc_comments
/// Diagnostic test to verify 3D shader compilation.
///
/// Run this test to verify that 3D fractal shaders can be loaded:
///   flutter test test/shader_3d_diagnostic_test.dart
///
/// This test attempts to load each 3D ray-marched shader and reports
/// success/failure with timing information.

import 'dart:ui' as ui;

import 'package:flutter_test/flutter_test.dart';

void main() {
  group('3D Shader Compilation Diagnostic', () {
    // All 3D ray-marched shaders from raymarched_3d_catalog.dart
    final List<String> shaderAssets = [
      'shaders/ifs_and_geometric/raymarched_3d/kifs_menger_gpu.frag',
      'shaders/ifs_and_geometric/raymarched_3d/kifs_sierpinski_tetra_gpu.frag',
      'shaders/ifs_and_geometric/raymarched_3d/kifs_koch_fold_gpu.frag',
      'shaders/ifs_and_geometric/raymarched_3d/kifs_snowflake_fold_gpu.frag',
      'shaders/3d_and_hypercomplex/quaternion_julia_3d_gpu.frag',
      'shaders/3d_and_hypercomplex/dual_quaternion_julia_gpu.frag',
      'shaders/3d_and_hypercomplex/mandelbox_shape_inversion_gpu.frag',
      'shaders/ifs_and_geometric/raymarched_3d/inversive_limit_set_3d_gpu.frag',
      'shaders/3d_and_hypercomplex/mandelbulb_time_modulated_gpu.frag',
      // Standalone 3D modules
      'shaders/legacy/mandelbulb.frag',
      'shaders/3d_and_hypercomplex/mandelbox_3d_gpu.frag',
      'shaders/ifs_and_geometric/menger_sponge_gpu.frag',
      'shaders/ifs_and_geometric/menger_3d_slice_gpu.frag',
      'shaders/3d_and_hypercomplex/quaternion_julia_2d_gpu.frag',
    ];

    for (final asset in shaderAssets) {
      test('loads $asset', () async {
        final stopwatch = Stopwatch()..start();
        try {
          final program = await ui.FragmentProgram.fromAsset(asset);
          stopwatch.stop();
          print('[OK] $asset compiled in ${stopwatch.elapsedMilliseconds}ms');
          expect(program, isNotNull);
        } catch (e) {
          stopwatch.stop();
          print(
              '[FAIL] $asset failed after ${stopwatch.elapsedMilliseconds}ms: $e');
          rethrow;
        }
      }, timeout: const Timeout(Duration(seconds: 60)));
    }
  });
}

import 'dart:io';

import 'package:flutter_fractals/core/modules/builders/escape_time_catalog.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:yaml/yaml.dart';

void main() {
  late final Set<String> declaredShaderAssets;

  setUpAll(() {
    final pubspec = loadYaml(File('pubspec.yaml').readAsStringSync()) as YamlMap;
    final flutter = pubspec['flutter'] as YamlMap;
    declaredShaderAssets = (flutter['shaders'] as YamlList).cast<String>().toSet();
  });

  test('declared strange-attractor shader assets exist on disk', () {
    final strangeAttractorAssets = declaredShaderAssets
        .where((asset) => asset.startsWith('shaders/strange_attractors/'))
        .toList()
      ..sort();

    expect(strangeAttractorAssets, isNotEmpty);

    for (final asset in strangeAttractorAssets) {
      expect(File(asset).existsSync(), isTrue, reason: '$asset must exist');
    }
  });

  test('catalog strange-attractor shader assets are declared in pubspec', () {
    final catalogAssets = escapeTimeCatalog
        .map((config) => config.shaderAsset)
        .where((asset) => asset.startsWith('shaders/strange_attractors/'))
        .toList()
      ..sort();

    expect(catalogAssets, isNotEmpty);

    for (final asset in catalogAssets) {
      expect(declaredShaderAssets, contains(asset), reason: '$asset must be declared');
      expect(File(asset).existsSync(), isTrue, reason: '$asset must exist');
    }
  });
}

